import React, { useState, useEffect } from 'react'
import { pondService, environmentLogService, sensorService, notificationService } from '../../services/api'
import { buildAllThresholdAlerts } from '../../services/thresholdAlertService'
import { useAuth } from '../../context/AuthContext'
import '../../styles/dashboard.css'
import '../../styles/technician/technician-layout.css'
import '../../styles/technician/technician-dashboard.css'

export const TechnicianDashboard = () => {
  const { realtimeSensorData } = useAuth()
  const [monitoredPonds, setMonitoredPonds] = useState([])
  const [recentEnvironmentLogs, setRecentEnvironmentLogs] = useState([])
  const [sensors, setSensors] = useState([])
  const [notifications, setNotifications] = useState([])
  const [thresholdAlerts, setThresholdAlerts] = useState([])
  const [latestLogByPond, setLatestLogByPond] = useState({})
  const [thresholdsMap, setThresholdsMap] = useState({})
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  useEffect(() => {
    fetchDashboardData()
  }, [])

  const normalizeSensorType = (type) => String(type || '').trim().toLowerCase()

  const normalizeSensorStatus = (status) => {
    const value = String(status || '').trim().toUpperCase()
    if (['ACTIVE', 'ONLINE', 'HOAT_DONG'].includes(value)) return 'ACTIVE'
    return 'INACTIVE'
  }

  const formatDateTime = (raw) => {
    if (!raw) return '--'
    const date = new Date(raw)
    if (Number.isNaN(date.getTime())) return '--'
    return date.toLocaleString('vi-VN', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    })
  }

  const parseNotificationLevel = (item) => {
    const severity = String(item?.severity || item?.level || '').toLowerCase()
    const message = String(item?.message || '').toLowerCase()
    if (severity.includes('high') || severity.includes('critical') || message.includes('cảnh báo')) return 'canh-bao'
    if (severity.includes('info') || message.includes('thông báo')) return 'thong-bao'
    return 'du-lieu'
  }

  const fetchDashboardData = async () => {
    try {
      setLoading(true)
      setError(null)

      const [pondsRes, sensorsRes, notificationsRes] = await Promise.all([
        pondService.getAllPonds(),
        sensorService.getAllSensors(),
        notificationService.getNotifications().catch(() => ({ data: { data: [] } })),
      ])

      const ponds = pondsRes?.data?.data || []
      const allSensors = sensorsRes?.data?.data || []
      const allNotifications = notificationsRes?.data?.data || []

      setMonitoredPonds(ponds)
      // Fetch thresholds for all ponds
      const thresholds = await Promise.all(
        ponds.map(async (pond) => {
          try {
            const response = await environmentLogService.getThresholdsByPond(pond.pond_id)
            return {
              pondId: pond.pond_id,
              thresholds: response?.data?.data || null,
            }
          } catch (err) {
            return { pondId: pond.pond_id, thresholds: null }
          }
        })
      )

      const thresholdsMapLocal = {}
      thresholds.forEach(({ pondId, thresholds: thresh }) => {
        if (thresh) {
          thresholdsMapLocal[String(pondId)] = thresh
        }
      })
      setThresholdsMap(thresholdsMapLocal)

      setSensors(allSensors)
      setNotifications(allNotifications)

      const logGroups = await Promise.all(
        ponds.map(async (pond) => {
          try {
            const response = await environmentLogService.getByPondId(pond.pond_id)
            return {
              pond,
              logs: response?.data?.data || [],
            }
          } catch (logError) {
            return { pond, logs: [] }
          }
        })
      )

      const latestByPond = {}
      const flattenedLogs = []

      logGroups.forEach(({ pond, logs }) => {
        if (!logs.length) return
        const sorted = [...logs].sort(
          (a, b) =>
            new Date(b.logged_at || b.created_at || b.recorded_at || 0).getTime() -
            new Date(a.logged_at || a.created_at || a.recorded_at || 0).getTime()
        )

        latestByPond[pond.pond_id] = sorted[0]

        sorted.slice(0, 3).forEach((log) => {
          flattenedLogs.push({
            ...log,
            pond_id: pond.pond_id,
            pond_code: pond.pond_code,
            pond_name: pond.pond_name,
          })
        })
      })

      const sortedRecent = flattenedLogs
        .sort(
          (a, b) =>
            new Date(b.logged_at || b.created_at || b.recorded_at || 0).getTime() -
            new Date(a.logged_at || a.created_at || a.recorded_at || 0).getTime()
        )
        .slice(0, 6)

      setLatestLogByPond(latestByPond)
      setRecentEnvironmentLogs(sortedRecent)
    } catch (err) {
      setError('Lỗi tải dữ liệu')
      console.error(err)
    } finally {
      setLoading(false)
    }
  }

  const activeSensors = sensors.filter((item) => normalizeSensorStatus(item.status) === 'ACTIVE')

  const latestManualInput = recentEnvironmentLogs[0] || null

  const monitoringStats = {
    totalPonds: monitoredPonds.length,
    activeSensors: activeSensors.length,
    alertCount: notifications.length,
    recentManualLogs: recentEnvironmentLogs.length,
  }

  const hasPondAlert = (pond) => {
    const code = String(pond.pond_code || '').toLowerCase()
    const name = String(pond.pond_name || '').toLowerCase()
    return notifications.some((item) => {
      const message = String(item?.message || '').toLowerCase()
      return (code && message.includes(code)) || (name && message.includes(name))
    })
  }

  if (loading) {
    return (
      <div className="dashboard technician-dashboard technician-page-shell">
        <div className="flex-center page-loading">
          <div className="spinner"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="dashboard technician-dashboard technician-page-shell">
      <div className="technician-dashboard__header">
        <div>
          <h1>Dashboard</h1>
          <p>Tổng quan hoạt động ao nuôi và cảm biến theo thời gian thực</p>
        </div>
      </div>

      {error && <div className="alert alert-error">{error}</div>}

      <section className="technician-dashboard__stat-grid">
        <article className="technician-dashboard__stat-card">
          <p className="technician-dashboard__stat-label">Tổng ao đang phụ trách</p>
          <p className="technician-dashboard__stat-value">{monitoringStats.totalPonds}</p>
          <span className="technician-dashboard__stat-note">Ao nuôi</span>
        </article>
        <article className="technician-dashboard__stat-card">
          <p className="technician-dashboard__stat-label">Tổng cảm biến hoạt động</p>
          <p className="technician-dashboard__stat-value">{monitoringStats.activeSensors}</p>
          <span className="technician-dashboard__stat-note">Trạng thái ổn định</span>
        </article>
        <article className="technician-dashboard__stat-card technician-dashboard__stat-card--warning">
          <p className="technician-dashboard__stat-label">Cảnh báo hiện tại</p>
          <p className="technician-dashboard__stat-value">{monitoringStats.alertCount}</p>
          <span className="technician-dashboard__stat-note">Cần theo dõi</span>
        </article>
        <article className="technician-dashboard__stat-card">
          <p className="technician-dashboard__stat-label">Tổng số dữ liệu nhập tay gần đây</p>
          <p className="technician-dashboard__stat-value">{monitoringStats.recentManualLogs}</p>
          <span className="technician-dashboard__stat-note">{latestManualInput ? `Lần nhập gần nhất: ${formatDateTime(latestManualInput.logged_at || latestManualInput.created_at || latestManualInput.recorded_at)}` : 'Chưa có dữ liệu nhập tay'}</span>
        </article>
      </section>

      <section className="technician-dashboard__content-grid">
        <div className="technician-dashboard__main-column">
          <article className="technician-dashboard__panel">
            <div className="technician-dashboard__panel-head">
              <h2>Tổng quan ao giám sát</h2>
              <span>{monitoredPonds.length} ao</span>
            </div>

            {monitoredPonds.length > 0 ? (
              <div className="technician-dashboard__pond-grid">
                {monitoredPonds.slice(0, 6).map((pond) => {
                  const latestLog = latestLogByPond[pond.pond_id] || {}
                  const isAlert = hasPondAlert(pond)
                  const pondSensors = sensors.filter((item) => String(item.pond_id) === String(pond.pond_id))

                  return (
                    <article key={pond.pond_id} className="technician-dashboard__pond-card">
                      <div className="technician-dashboard__pond-head">
                        <h3>{pond.pond_code || `Ao ${pond.pond_id}`}</h3>
                        <span className={isAlert ? 'badge badge-warning' : 'badge badge-ok'}>
                          {isAlert ? 'Cảnh báo' : 'Bình thường'}
                        </span>
                      </div>
                      <p className="technician-dashboard__pond-name">{pond.pond_name || 'Ao nuôi'}</p>
                      <p className="technician-dashboard__pond-sensors">Số cảm biến: {pondSensors.length}</p>

                      <div className="technician-dashboard__pond-metrics">
                        <span>DO {Number.isFinite(Number(latestLog.oxygen)) ? Number(latestLog.oxygen).toFixed(1) : '--'} mg/L</span>
                        <span>pH {Number.isFinite(Number(latestLog.ph)) ? Number(latestLog.ph).toFixed(1) : '--'}</span>
                        <span>Nhiệt {Number.isFinite(Number(latestLog.temperature)) ? Number(latestLog.temperature).toFixed(1) : '--'}°C</span>
                        <span>Độ mặn {Number.isFinite(Number(latestLog.salinity)) ? Number(latestLog.salinity).toFixed(1) : '--'} ppt</span>
                        <span>Độ đục {Number.isFinite(Number(latestLog.turbidity)) ? Number(latestLog.turbidity).toFixed(1) : '--'} NTU</span>
                      </div>
                    </article>
                  )
                })}
              </div>
            ) : (
              <p className="technician-dashboard__empty">Bạn chưa được phân công ao nào.</p>
            )}
          </article>
        </div>

        <div className="technician-dashboard__side-column">
          <article className="technician-dashboard__panel">
            <div className="technician-dashboard__panel-head">
              <h2>Dữ liệu nhập tay gần đây</h2>
              <a href="/technician/environment">Mở trang môi trường</a>
            </div>

            {recentEnvironmentLogs.length > 0 ? (
              <div className="technician-dashboard__table-wrap">
                <table className="technician-dashboard__table">
                  <thead>
                    <tr>
                      <th>Thời gian nhập</th>
                      <th>Ao</th>
                      <th>pH</th>
                      <th>Nhiệt độ</th>
                      <th>DO</th>
                      <th>Độ mặn</th>
                      <th>Độ đục</th>
                    </tr>
                  </thead>
                  <tbody>
                    {recentEnvironmentLogs.map((log, index) => (
                      <tr key={`${log.environment_log_id || log.log_id || 'log'}-${index}`}>
                        <td>{formatDateTime(log.logged_at || log.created_at || log.recorded_at)}</td>
                        <td>{log.pond_code || log.pond_name || '--'}</td>
                        <td>{Number.isFinite(Number(log.ph)) ? Number(log.ph).toFixed(1) : '--'}</td>
                        <td>{Number.isFinite(Number(log.temperature)) ? Number(log.temperature).toFixed(1) : '--'}°C</td>
                        <td>{Number.isFinite(Number(log.oxygen)) ? Number(log.oxygen).toFixed(1) : '--'} mg/L</td>
                        <td>{Number.isFinite(Number(log.salinity)) ? Number(log.salinity).toFixed(1) : '--'} ppt</td>
                        <td>{Number.isFinite(Number(log.turbidity)) ? Number(log.turbidity).toFixed(1) : '--'} NTU</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            ) : (
              <p className="technician-dashboard__empty">Chưa có dữ liệu nhập tay gần đây.</p>
            )}
          </article>

          <article className="technician-dashboard__panel">
            <div className="technician-dashboard__panel-head">
              <h2>Cảnh báo và thông báo</h2>
              <span>{notifications.length} mục</span>
            </div>

            {notifications.length > 0 ? (
              <ul className="technician-dashboard__alert-list">
                {notifications.slice(0, 6).map((item) => {
                  const level = parseNotificationLevel(item)
                  return (
                    <li key={item.notification_id || item.id} className={`alert-item alert-item--${level}`}>
                      <div>
                        <p>{item.message || 'Thông báo hệ thống'}</p>
                        <span>{formatDateTime(item.created_at || item.createdAt)}</span>
                      </div>
                    </li>
                  )
                })}
              </ul>
            ) : (
              <p className="technician-dashboard__empty">Hiện chưa có cảnh báo nào.</p>
            )}
          </article>
        </div>
      </section>
    </div>
  )
}

export default TechnicianDashboard
